// ─── Shared sub-components ────────────────────────────────────────────────────

function ColorPicker({
  label,
  value,
  onChange,
  id,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  id: string;
}) {
  return (
    <div className="flex flex-col gap-1.5">
      <Label htmlFor={id}>{label}</Label>
      <div className="flex items-center gap-2">
        <div
          className="size-8 rounded border border-input overflow-hidden cursor-pointer shrink-0"
          style={{ backgroundColor: value }}
        >
          <input
            id={id}
            type="color"
            value={value}
            onChange={(e) => onChange(e.target.value)}
            className="opacity-0 w-full h-full cursor-pointer"
          />
        </div>
        <span className="text-sm text-muted-foreground font-mono">{value.toUpperCase()}</span>
      </div>
    </div>
  );
}

// ─── Widget config forms ──────────────────────────────────────────────────────

function ScrollingTextConfig() {
  const [text, setText] = React.useState("");
  const [bgColor, setBgColor] = React.useState("#000000");
  const [textColor, setTextColor] = React.useState("#ffffff");

  return (
    <div className="flex flex-col gap-4">
      <div className="flex flex-col gap-2">
        <Label htmlFor="scroll-text">Text</Label>
        <Input
          id="scroll-text"
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Enter scrolling text..."
        />
      </div>
      <div className="flex gap-6">
        <ColorPicker id="scroll-bg" label="Background Color" value={bgColor} onChange={setBgColor} />
        <ColorPicker id="scroll-text-color" label="Text Color" value={textColor} onChange={setTextColor} />
      </div>
      {text && (
        <div
          className="rounded px-3 py-2 text-sm font-medium truncate"
          style={{ backgroundColor: bgColor, color: textColor }}
        >
          {text}
        </div>
      )}
    </div>
  );
}

function RotatingTextConfig() {
  const [panels, setPanels] = React.useState(["", "", ""]);
  const [bgColor, setBgColor] = React.useState("#000000");
  const [textColor, setTextColor] = React.useState("#ffffff");

  function updatePanel(index: number, value: string) {
    setPanels((prev) => prev.map((p, i) => (i === index ? value : p)));
  }

  function addPanel() {
    if (panels.length < 4) setPanels((prev) => [...prev, ""]);
  }

  function removePanel(index: number) {
    if (panels.length > 3) setPanels((prev) => prev.filter((_, i) => i !== index));
  }

  return (
    <div className="flex flex-col gap-4">
      <div className="flex flex-col gap-2">
        <Label>Panels</Label>
        <div className="flex flex-col gap-2">
          {panels.map((panel, index) => (
            <div key={index} className="flex items-center gap-2">
              <span className="text-xs text-muted-foreground w-6 shrink-0 text-right">{index + 1}.</span>
              <Textarea
                value={panel}
                onChange={(e) => updatePanel(index, e.target.value)}
                placeholder={`Panel ${index + 1} text...`}
                className="resize-none min-h-0 h-16 text-sm"
              />
              <button
                type="button"
                onClick={() => removePanel(index)}
                disabled={panels.length <= 3}
                className="text-muted-foreground hover:text-destructive transition-colors disabled:opacity-30 disabled:cursor-not-allowed shrink-0"
              >
                <Trash2 className="size-4" />
              </button>
            </div>
          ))}
        </div>
        {panels.length < 4 && (
          <Button type="button" variant="outline" size="sm" className="w-fit gap-1.5" onClick={addPanel}>
            <Plus className="size-3.5" />
            Add Panel
          </Button>
        )}
      </div>
      <div className="flex gap-6">
        <ColorPicker id="rotate-bg" label="Background Color" value={bgColor} onChange={setBgColor} />
        <ColorPicker id="rotate-text-color" label="Text Color" value={textColor} onChange={setTextColor} />
      </div>
    </div>
  );
}

function ImageWidgetConfig() {
  const [images, setImages] = React.useState<(File | null)[]>([null]);
  const inputRefs = [
    React.useRef<HTMLInputElement>(null),
    React.useRef<HTMLInputElement>(null),
    React.useRef<HTMLInputElement>(null),
    React.useRef<HTMLInputElement>(null),
  ];

  function handleFileChange(index: number, file: File | null) {
    setImages((prev) => {
      const next = [...prev];
      next[index] = file;
      // Auto-add a new empty slot if this is the last one and under the limit
      if (file && index === next.length - 1 && next.length < 4) {
        next.push(null);
      }
      return next;
    });
  }

  function removeImage(index: number) {
    setImages((prev) => {
      const next = prev.filter((_, i) => i !== index);
      return next.length === 0 ? [null] : next;
    });
  }

  return (
    <div className="flex flex-col gap-3">
      <div className="flex flex-col gap-1">
        <Label>Images</Label>
        <p className="text-xs text-muted-foreground">Upload 1–4 images. Recommended size: 540 × 1920px (9:32 ratio).</p>
      </div>
      <div className="grid grid-cols-4 gap-3">
        {images.map((file, index) => (
          <div key={index} className="flex flex-col gap-1.5">
            <input
              ref={inputRefs[index]}
              type="file"
              accept=".jpg,.jpeg,.png"
              className="hidden"
              onChange={(e) => handleFileChange(index, e.target.files?.[0] ?? null)}
            />
            {file ? (
              <div className="relative aspect-[9/16] rounded-md border overflow-hidden bg-muted group">
                <img
                  src={URL.createObjectURL(file)}
                  alt={`Image ${index + 1}`}
                  className="absolute inset-0 w-full h-full object-cover"
                />
                <button
                  type="button"
                  onClick={() => removeImage(index)}
                  className="absolute top-1 right-1 rounded-full bg-black/60 p-0.5 text-white opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <Trash2 className="size-3" />
                </button>
              </div>
            ) : (
              <button
                type="button"
                onClick={() => inputRefs[index].current?.click()}
                className="aspect-[9/16] rounded-md border-2 border-dashed border-border hover:border-primary/50 hover:bg-muted/50 transition-colors flex flex-col items-center justify-center gap-1"
              >
                <Plus className="size-4 text-muted-foreground" />
                <span className="text-xs text-muted-foreground">Add</span>
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── Generic widget zone section ─────────────────────────────────────────────

function WidgetZoneConfig({ label, description }: { label: string; description: string }) {
  const [selectedWidget, setSelectedWidget] = React.useState<WidgetType | null>(null);

  return (
    <div className="flex flex-col gap-4 pt-2 border-t">
      <div className="flex flex-col gap-1">
        <p className="text-sm font-medium">{label}</p>
        <p className="text-xs text-muted-foreground">{description}</p>
      </div>

      <div className="grid grid-cols-3 gap-3">
        {widgetOptions.map((widget) => {
          const isSelected = selectedWidget === widget.id;
          return (
            <button
              key={widget.id}
              type="button"
              onClick={() => setSelectedWidget(widget.id)}
              className={[
                "flex flex-col gap-2 rounded-lg border-2 p-3 text-left transition-colors",
                isSelected
                  ? "border-primary bg-primary/5"
                  : "border-border hover:border-muted-foreground/40",
              ].join(" ")}
            >
              {widget.icon}
              <div className="flex flex-col gap-0.5">
                <p className="text-xs font-semibold leading-tight">{widget.name}</p>
                <p className="text-xs text-muted-foreground leading-snug">{widget.description}</p>
              </div>
            </button>
          );
        })}
      </div>

      {selectedWidget === "scrolling-text" && <ScrollingTextConfig />}
      {selectedWidget === "rotating-text" && <RotatingTextConfig />}
      {selectedWidget === "image" && <ImageWidgetConfig />}
    </div>
  );
}

